34	// RoutingMigrationError signals that the loaded config carries the
35	// removed agent.routing.default_harness field (bead ddx-87fb72c2). The
36	// field is gone for good; configs must be migrated before DDx will
37	// load them.
38	type RoutingMigrationError struct {
39		Field string
40		Path  string
41	}
42	
43	func (e *RoutingMigrationError) Error() string {
44		return fmt.Sprintf(
45			"%s: %s has been removed. "+
46				"Migration: delete the field. The top-level agent.harness is a "+
47				"tie-break preference, not a default override. "+
48				"See docs/migrations/routing-config.md.",
49			e.Path, e.Field)
50	}
51	
52	// checkRoutingMigration parses the raw config bytes and reports the
53	// breaking change cases for agent.routing. Returns a hard error when
54	// agent.routing.default_harness is present; emits a one-time process
55	// warning when profile_ladders or model_overrides are set (because
56	// those fields are now opt-in via --escalate / --override-model).
57	func checkRoutingMigration(path string, data []byte) error {
58		var raw map[string]any
59		if err := yaml.Unmarshal(data, &raw); err != nil {
60			return nil // YAML errors surface from the validator below
61		}
62		agent, _ := raw["agent"].(map[string]any)
63		if agent == nil {
64			return nil
65		}
66		routing, _ := agent["routing"].(map[string]any)
67		if routing == nil {
68			return nil
69		}
70		if _, ok := routing["default_harness"]; ok {
71			return &RoutingMigrationError{
72				Field: "agent.routing.default_harness",
73				Path:  path,
74			}
75		}
76		if _, ok := routing["profile_ladders"]; ok {
77			warnRoutingOnce("profile_ladders",
78				"warning: agent.routing.profile_ladders is opt-in. "+
79					"It is consulted only when --escalate is passed; "+
80					"the default execute path ignores it. "+
81					"See docs/migrations/routing-config.md.")
82		}
83		if _, ok := routing["model_overrides"]; ok {
84			warnRoutingOnce("model_overrides",
85				"warning: agent.routing.model_overrides is opt-in. "+
86					"It is consulted only when --override-model is passed; "+
87					"the default execute path ignores it. "+
88					"See docs/migrations/routing-config.md.")
89		}
90		return nil
91	}
