121	// Load loads configuration using the new simplified approach
122	func Load() (*Config, error) {
123		workingDir, err := os.Getwd()
124		if err != nil {
125			return nil, fmt.Errorf("failed to get working directory: %w", err)
126		}
127		return LoadWithWorkingDir(workingDir)
128	}
129	
130	// LoadWithWorkingDir loads configuration from a specific working directory
131	func LoadWithWorkingDir(workingDir string) (*Config, error) {
132		if workingDir == "" {
133			var err error
134			workingDir, err = os.Getwd()
135			if err != nil {
136				return nil, fmt.Errorf("failed to get working directory: %w", err)
137			}
138		}
139	
140		// Use the new ConfigLoader to load from .ddx/config.yaml only
141		loader, err := NewConfigLoaderWithWorkingDir(workingDir)
142		if err != nil {
143			return nil, fmt.Errorf("failed to create config loader: %w", err)
144		}
145	
146		// Pre-validation migration check: surface a friendly hard error for
147		// removed-field cases (agent.routing.default_harness) and emit
148		// one-time warnings for opt-in fields (profile_ladders,
149		// model_overrides) before the schema validator sees the file. This
150		// happens before LoadConfig so the migration message is what the
151		// operator sees.
152		configPath := filepath.Join(workingDir, ".ddx", "config.yaml")
153		if data, readErr := os.ReadFile(configPath); readErr == nil {
154			if migErr := checkRoutingMigration(configPath, data); migErr != nil {
155				return nil, migErr
156			}
157		}
158	
159		config, err := loader.LoadConfig()
160		if err != nil {
161			// If no config file exists, return default config
162			if os.IsNotExist(err) || strings.Contains(err.Error(), "no configuration file found") {
163				config = DefaultNewConfig()
164			} else {
165				return nil, err
166			}
167		}
168	
169		// Apply defaults to ensure complete configuration
170		config.ApplyDefaults()
171		if config.Agent != nil && config.Agent.Routing != nil &&
172			len(config.Agent.Routing.ProfilePriority) > 0 {
173			fmt.Fprintln(os.Stderr, "warning: agent.routing.profile_priority is deprecated; use agent.routing.profile_ladders.default instead")
174		}
175	
176		// Override library path with environment variable if set
177		if envLibraryPath := os.Getenv("DDX_LIBRARY_BASE_PATH"); envLibraryPath != "" {
178			config.Library.Path = envLibraryPath
179		}
180	
181		// Validate the final configuration
182		if err := config.Validate(); err != nil {
183			return nil, fmt.Errorf("configuration validation failed: %w", err)
184		}
185	
186		return config, nil
187	}
188	
189	// Validate validates the configuration structure and values (simplified)
190	func (c *Config) Validate() error {
191		var errors []*ConfigError
192	
193		// Validate version
194		if c.Version == "" {
195			errors = append(errors, &ConfigError{
196				Field:      "version",
197				Message:    "version is required",
198				Suggestion: "add 'version: \"1.0\"' to your config",
199			})
200		}
201	
202		// Validate library configuration
203		if c.Library != nil && c.Library.Repository != nil {
204			if c.Library.Repository.URL == "" {
205				errors = append(errors, &ConfigError{
206					Field:      "library.repository.url",
207					Message:    "library repository URL is required",
208					Suggestion: "add a valid Git repository URL",
209				})
210			}
211	
212			if c.Library.Repository.Branch == "" {
213				errors = append(errors, &ConfigError{
214					Field:      "library.repository.branch",
215					Message:    "library repository branch is required",
216					Suggestion: "add 'branch: \"main\"' or another valid branch name",
217				})
218			}
219		}
220	
221		if len(errors) > 0 {
222			return &ValidationError{Errors: errors}
223		}
224	
225		return nil
226	}
