441					}
442					for _, c := range activeCooldowns {
443						cd := routeStatusCooldownJSON{
444							Route:         c.route,
445							Provider:      c.provider,
446							CooldownUntil: c.cooldownUntil.UTC().Format(time.RFC3339),
447						}
448						if !c.failedAt.IsZero() {
449							cd.FailedAt = c.failedAt.UTC().Format(time.RFC3339)
450						}
451						payload.ActiveCooldowns = append(payload.ActiveCooldowns, cd)
452					}
453					enc := json.NewEncoder(cmd.OutOrStdout())
454					enc.SetIndent("", "  ")
455					return enc.Encode(payload)
456				}
457	
458				out := cmd.OutOrStdout()
459	
460				// --- Section 1: Route Table ---
461				for i, entry := range report.Routes {
462					if i > 0 {
463						fmt.Fprintln(out)
464					}
465	
466					selectedProvider := ""
467					selectedModel := ""
