473						}
474					}
475	
476					strategy := entry.Strategy
477					if strategy == "" {
478						strategy = "first-available"
479					}
480	
481					fmt.Fprintf(out, "Route: %s\n", entry.Model)
482					fmt.Fprintf(out, "Strategy: %s\n", strategy)
