487					}
488	
489					fmt.Fprintf(out, "%-12s %-32s %-10s %-10s %-10s %-12s %s\n",
490						"PROVIDER", "MODEL", "HEALTH", "SCORE", "RELIABILITY", "LATENCY_MS", "REASON")
491					for _, cand := range entry.Candidates {
492						health := "available"
493						reason := ""
494						if cand.Cooldown != nil && !cand.Cooldown.Until.IsZero() {
495							health = "cooldown"
