705						if cappedReport, capped := costCapTripped(); capped {
706							cappedReport.BeadID = beadID
707							return cappedReport, nil
708						}
709					}
710					return report, err
711				}
712	
713				// Profile escalation: configured profile ladder bounded by MinTier/MaxTier.
714				tiers := agent.ResolveProfileLadder(routingCfg, profile, spec.MinTier, spec.MaxTier)
715				if len(tiers) == 0 {
716					return agent.ExecuteBeadReport{
717						BeadID: beadID,
718						Status: agent.ExecuteBeadStatusExecutionFailed,
719						Detail: "execute-loop: no tiers in range (check min_tier / max_tier)",
720					}, nil
721				}
722	
723				beadStore := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
724				svc, svcErr := agent.NewServiceFromWorkDir(projectRoot)
725				if svcErr != nil {
726					return agent.ExecuteBeadReport{
727						BeadID: beadID,
728						Status: agent.ExecuteBeadStatusExecutionFailed,
729						Detail: "execute-loop: failed to initialize routing service: " + svcErr.Error(),
730					}, nil
731				}
732				var lastReport agent.ExecuteBeadReport
733				var escalationAttempts []escalation.TierAttemptRecord
734				requestedTier := string(tiers[0])
735	
736				for tierIdx, tier := range tiers {
737					// Catalog-driven tier resolution (ddx-5538aa5b): walk catalog
738					// surfaces (or model_overrides if set) to produce concrete
739					// (harness, model) candidates. Avoids the prior failure mode
740					// where the literal tier name ("cheap"/"standard"/"smart") was
741					// passed as Model and resolved to no harness/no model.
742					candidates := agent.ResolveTierCandidates(routingCfg, agent.BuiltinCatalog, tier)
743	
744					var dec *agentlib.RouteDecision
745					var routeErr error
746					var skipReasons []string
747					for _, cand := range candidates {
748						req := agentlib.RouteRequest{
749							Profile:   profile,
750							Provider:  spec.Provider,
751							Reasoning: agentlib.Reasoning(spec.Effort),
752						}
753						if cand.Harness != "" {
754							req.Harness = cand.Harness
755						}
756						if cand.Model != "" {
757							req.Model = cand.Model
758						}
759						d, err := svc.ResolveRoute(ctx, req)
760						if err != nil {
761							skipReasons = append(skipReasons, formatTierCandidateRejection(cand, err.Error()))
762							continue
763						}
764						if !workerHarnessHealthy(ctx, svc, d.Harness) {
765							skipReasons = append(skipReasons, formatTierCandidateRejection(cand, "provider cooldown"))
766							continue
767						}
768						dec = d
769						break
770					}
771					if dec == nil {
772						if len(candidates) == 0 {
773							skipReasons = []string{"tier has no candidates in catalog and no model_overrides entry"}
774						}
775						routeErr = fmt.Errorf("no viable harness")
776					}
777					probeResult := "ok"
778					if routeErr != nil {
779						probeResult = "no viable provider"
780						detail := strings.Join(skipReasons, "\n")
781						if detail == "" {
782							detail = "no viable harness found"
783						}
784						_ = beadStore.AppendEvent(beadID, bead.BeadEvent{
785							Kind:      "tier-attempt",
786							Summary:   "skipped",
787							Body:      escalation.FormatTierAttemptBody(string(tier), "", "", probeResult, detail),
788							Actor:     "ddx",
789							Source:    "ddx agent execute-loop",
790							CreatedAt: time.Now().UTC(),
791						})
792						escalationAttempts = append(escalationAttempts, escalation.TierAttemptRecord{
793							Tier:   string(tier),
794							Status: "skipped",
795						})
796						continue
797					}
798	
799					report, attemptErr := singleTierAttempt(ctx, beadID, tier, dec.Harness, dec.Provider, dec.Model)
800					if attemptErr != nil {
801						report = agent.ExecuteBeadReport{
802							BeadID:           beadID,
803							Tier:             string(tier),
804							Harness:          dec.Harness,
805							Model:            dec.Model,
806							Status:           agent.ExecuteBeadStatusExecutionFailed,
807							Detail:           attemptErr.Error(),
808							ProbeResult:      probeResult,
809							RequestedProfile: profile,
810							RequestedTier:    requestedTier,
811							ResolvedTier:     string(tier),
812							EscalationCount:  tierIdx,
813							FinalTier:        string(tier),
814						}
815					} else {
816						report.ProbeResult = probeResult
817						report.RequestedProfile = profile
818						report.RequestedTier = requestedTier
819						report.ResolvedTier = string(tier)
820						report.EscalationCount = tierIdx
821						report.FinalTier = string(tier)
822					}
823					lastReport = report
824					escalationAttempts = append(escalationAttempts, escalation.TierAttemptRecord{
825						Tier:       string(tier),
826						Harness:    report.Harness,
827						Model:      report.Model,
828						Status:     report.Status,
829						CostUSD:    report.CostUSD,
830						DurationMS: report.DurationMS,
831					})
832	
833					_ = beadStore.AppendEvent(beadID, bead.BeadEvent{
834						Kind:      "tier-attempt",
835						Summary:   report.Status,
836						Body:      escalation.FormatTierAttemptBody(string(tier), report.Harness, report.Model, probeResult, report.Detail),
837						Actor:     "ddx",
838						Source:    "ddx agent execute-loop",
839						CreatedAt: time.Now().UTC(),
840					})
841	
842					if report.Status == agent.ExecuteBeadStatusSuccess {
843						accumulateBilledCost(report)
844						_ = escalation.AppendEscalationSummaryEvent(beadStore, beadID, "ddx", escalationAttempts, string(tier), time.Now().UTC())
845						if cappedReport, capped := costCapTripped(); capped {
846							cappedReport.BeadID = beadID
847							return cappedReport, nil
848						}
