93	// Type aliases for smooth transition
94	type Config = NewConfig
95	type Repository = RepositoryConfig
96	
97	// ConfigError represents a single configuration error
98	type ConfigError struct {
99		Field      string
100		Value      string
101		Message    string
102		Suggestion string
103	}
104	
105	func (e *ConfigError) Error() string {
106		return fmt.Sprintf("%s: %s", e.Field, e.Message)
107	}
108	
109	// ValidationError represents multiple configuration errors
110	type ValidationError struct {
111		Errors []*ConfigError
112	}
113	
114	func (e *ValidationError) Error() string {
115		if len(e.Errors) == 1 {
116			return e.Errors[0].Error()
117		}
118		return fmt.Sprintf("%d configuration errors found", len(e.Errors))
119	}
