752						}
753						if cand.Harness != "" {
754							req.Harness = cand.Harness
755						}
756						if cand.Model != "" {
757							req.Model = cand.Model
758						}
759						d, err := svc.ResolveRoute(ctx, req)
760						if err != nil {
761							skipReasons = append(skipReasons, formatTierCandidateRejection(cand, err.Error()))
762							continue
763						}
764						if !workerHarnessHealthy(ctx, svc, d.Harness) {
765							skipReasons = append(skipReasons, formatTierCandidateRejection(cand, "provider cooldown"))
766							continue
767						}
768						dec = d
769						break
770					}
771					if dec == nil {
772						if len(candidates) == 0 {
773							skipReasons = []string{"tier has no candidates in catalog and no model_overrides entry"}
774						}
775						routeErr = fmt.Errorf("no viable harness")
776					}
777					probeResult := "ok"
778					if routeErr != nil {
779						probeResult = "no viable provider"
780						detail := strings.Join(skipReasons, "\n")
