827						Model:      report.Model,
828						Status:     report.Status,
829						CostUSD:    report.CostUSD,
830						DurationMS: report.DurationMS,
831					})
832	
833					_ = beadStore.AppendEvent(beadID, bead.BeadEvent{
834						Kind:      "tier-attempt",
835						Summary:   report.Status,
836						Body:      escalation.FormatTierAttemptBody(string(tier), report.Harness, report.Model, probeResult, report.Detail),
837						Actor:     "ddx",
838						Source:    "ddx agent execute-loop",
839						CreatedAt: time.Now().UTC(),
840					})
841	
842					if report.Status == agent.ExecuteBeadStatusSuccess {
843						accumulateBilledCost(report)
844						_ = escalation.AppendEscalationSummaryEvent(beadStore, beadID, "ddx", escalationAttempts, string(tier), time.Now().UTC())
