861						report.Detail = "infrastructure failure (deferred): " + report.Detail
862						_ = escalation.AppendEscalationSummaryEvent(beadStore, beadID, "ddx", escalationAttempts, "", time.Now().UTC())
863						if cappedReport, capped := costCapTripped(); capped {
864							cappedReport.BeadID = beadID
865							return cappedReport, nil
866						}
867						return report, nil
868					}
869					accumulateBilledCost(report)
870					if report.Status == agent.ExecuteBeadStatusExecutionFailed {
871						_ = svc.RecordRouteAttempt(ctx, agentlib.RouteAttempt{
